import sys

def caesar(text, shift, encode):
    result = []
    direction = shift if encode else -shift
    for ch in text:
        if ch.isalpha():
            base = ord('A') if ch.isupper() else ord('a')
            result.append(chr((ord(ch) - base + direction) % 26 + base))
        else:
            result.append(ch)
    return ''.join(result)

